async def upload_preflight_middleware(request: Request, call_next):
    rid = request.headers.get("x-request-id")
    if not rid or len(rid) > 128:
        rid = uuid.uuid4().hex
    request.state.request_id = rid

    if request.url.path == "/api/upload" and request.method.upper() == "POST":
        content_type = request.headers.get("content-type", "")
        if not content_type:
            exc = UploadError(400, "UPLOAD_CONTENT_TYPE_MISSING", "Content-Type header is required.")
            log_attempt(request, "failure", error_code=exc.code, status_code=exc.status_code)
            return error_response(request, exc)

        lowered = content_type.lower()
        if not lowered.startswith("multipart/form-data"):
            exc = UploadError(400, "UPLOAD_BAD_CONTENT_TYPE", "Use multipart/form-data.")
            log_attempt(request, "failure", error_code=exc.code, status_code=exc.status_code)
            return error_response(request, exc)

        if "boundary=" not in lowered:
            exc = UploadError(400, "UPLOAD_MULTIPART_BOUNDARY_MISSING", "Multipart boundary is missing.")
            log_attempt(request, "failure", error_code=exc.code, status_code=exc.status_code)
            return error_response(request, exc)

        content_length = request.headers.get("content-length")
        if content_length is not None:
            try:
                request_bytes = int(content_length)
            except ValueError:
                exc = UploadError(400, "UPLOAD_CONTENT_LENGTH_INVALID", "Content-Length is invalid.")
                log_attempt(request, "failure", error_code=exc.code, status_code=exc.status_code)
                return error_response(request, exc)

            if request_bytes < 0:
                exc = UploadError(400, "UPLOAD_CONTENT_LENGTH_INVALID", "Content-Length is invalid.")
                log_attempt(request, "failure", error_code=exc.code, status_code=exc.status_code)
                return error_response(request, exc)

            # Reject known-overlarge requests before multipart parsing consumes resources.
            if request_bytes > MAX_REQUEST_BYTES:
                exc = UploadError(
                    413,
                    "UPLOAD_REQUEST_TOO_LARGE",
                    "Request body is too large.",
                    {"max_file_bytes": MAX_FILE_BYTES},
                )
                log_attempt(request, "failure", error_code=exc.code, status_code=exc.status_code)
                return error_response(request, exc)

    response = await call_next(request)
    response.headers["X-Request-ID"] = rid
    return response


