        # loading the whole file into memory.
        first_chunk = await read_upload_chunk(file, MAGIC_READ_BYTES)
        if not first_chunk:
            raise UploadError(400, "UPLOAD_EMPTY_FILE", "Uploaded file is empty.")

        total_bytes = len(first_chunk)
