        final_name, final_path = build_final_path(upload_id, image_type)
        tmp_path, fd = await anyio.to_thread.run_sync(create_temp_file, upload_id)

        hasher = hashlib.sha256()

        await anyio.to_thread.run_sync(write_all, fd, first_chunk)
        hasher.update(first_chunk)

        # Stream remaining content in bounded chunks and enforce the limit even
        # when Content-Length is missing or lies.
        while True:
            chunk = await read_upload_chunk(file, CHUNK_BYTES)
            if not chunk:
