            total_bytes += len(chunk)
            if total_bytes > MAX_FILE_BYTES:
                raise UploadError(
                    413,
                    "UPLOAD_FILE_TOO_LARGE",
                    "Uploaded file exceeds the 10MB limit.",
                    {"max_file_bytes": MAX_FILE_BYTES, "received_bytes": total_bytes},
